  ('pukao-77f8735d-moex-00012', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '衛生福利部是在立法院三讀通過何項法案後，於何年正式成立？', '["中央行政機關組織改造法，2008年", "衛生福利部組織法，2008年", "中央行政機關組織改造法，2013年", "衛生福利部組織法，2013年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00013', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '自民國 88 年政府完成精簡臺灣省政府組織後，中央與地方衛生行政組織間的關係，下列敘述何 者最不適當？', '["目前衛生行政組織已簡化為中央、直轄市及縣（市）二級", "中央衛生福利部與地方衛生局間之關係，為垂直式一條鞭制的系統管理模式", "根據地方制度法，各地方政府可依內政部準則所訂定之組織自治條例，予以所轄衛生相關單位 適當名稱", "全國各鄉鎮市區均設有衛生所（或健康服務中心）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00014', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '某縣市衛生局於轄區進行餐廳衛生現場稽查，發現A餐廳未依規定保存食品，且餐廳廚房的地面、 料理餐點檯面及餐具清洗設施有污穢不潔情形，乃對餐廳業者開罰並要求其限期改善。請問下列 敘述何者最不適當？', '["對業者開立並送達之裁處書，為具強制力之行政處分", "於開立裁處書前，衛生局應給予業者陳述意見之機會，逕行開罰實有不當", "業者如對開罰內容不服，可另循訴願、行政訴訟等程序請求救濟", "衛生局之作為乃為依法行政之作為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00015', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '於登革熱疫情期間，為有效控制傳播，衛生主管機關於必要時，可以指定隔離治療機構對感染者 施行隔離治療。此措施所依據之行政法原則，下列何者最適當？', '["平等原則", "信賴保護原則", "比例原則", "正當程序原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00016', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '國民健康署定義我國成人健康體位，有其依據的指標及體位分類標準，下列內容何者最正確？', '["以身體質量指數做為衡量18歲以上成人健康體位之指標", "身體質量指數等於公斤／公尺", "成人身體質量指數大於或等於29則為肥胖", "成人身體質量指數小於或等於18.5則為過輕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00017', 'pukao-77f8735d', 'pukao-77f8735d-moex-114-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '依據民國112年公布修訂並實施至今的菸害防制法，下列內容何者正確？', '["未滿18歲之人或孕婦禁止吸菸", "電子煙被歸類為類菸品，於禁止吸菸的場所依法不得使用", "菸品容器警示圖文標示面積增加為50%", "開放加熱菸之輸入、販賣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "a166b3a132a4", "answer_pdf_sha1": "de8cffdf0241", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "424", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
